    protected AgreementHeaderTmp initializeAgreementHeaderTmp()
{
    AgreementHeaderTmp               agreementHeaderTmp;
    PaymTerm                         patmterm;
    ETG_PurchTableTrade              eTG_PurchTableTrade;
    purchTable                       purchTable;
    AgreementHeader                  agreementHeader;
    ETG_purchAgreementHeader         eTG_purchAgreementHeader;
    AgreementClassification          agreementClassification;
    PurchAgreementHeader             purchAgreementHeader;
    PurchAgreementHeaderHistory        purchAgreementHeaderHistory;
    LogisticsElectronicAddress          logisticsElectronicAddresBuyer,logisticsElectronicAddresSeller;
    Logisticspostaladdress                  logisticspostaladdress;
    LogisticsLocation                       LogisticsLocation;
    DirPartyTable                       dirpartySeller,dirpartyBuyer;
    ETG_PurchaseAgreementHeader         purchaseAgreementHeaderETG;

    AgreementConfirmationDPLineCreationParameters _parameters;
    AgreementHeaderTmp = next initializeAgreementHeaderTmp();

    select firstonly purchaseAgreementHeaderETG
    where purchaseAgreementHeaderETG.PurchAgreementId == AgreementHeaderTmp.AgreementId;

    select purchAgreementHeader
    where purchAgreementHeader.PurchNumberSequence == purchaseAgreementHeaderETG.PurchAgreementId;


    select agreementHeader
    where agreementHeader.RecId == purchAgreementHeader.RecId;

    select purchTable
    where purchtable.MatchingAgreement == agreementHeader.RecId;


    select firstonly dirpartyBuyer
    join logisticsElectronicAddresBuyer
    where dirpartyBuyer.RecId == logisticsElectronicAddresBuyer.PrivateForParty
    join logisticsLocation
    where logisticsElectronicAddresBuyer.Location == logisticsLocation.RecId
    join logisticspostaladdress
    where LogisticsLocation.RecId == logisticspostaladdress.Location
    join eTG_PurchTableTrade
        where logisticspostaladdress.RecId == eTG_PurchTableTrade.BuyerDeliveryAddress
    && eTG_PurchTableTrade.PurchId == purchTable.PurchId;

    Select firstonly dirpartyseller
    join logisticsElectronicAddresseller
    where dirpartyBuyer.RecId == logisticsElectronicAddresBuyer.PrivateForParty
    join logisticsLocation
    where logisticsElectronicAddresBuyer.Location == logisticsLocation.RecId
    join logisticspostaladdress
    where LogisticsLocation.RecId == logisticspostaladdress.Location
    join eTG_PurchTableTrade
        where logisticspostaladdress.RecId == eTG_PurchTableTrade.SellerDeliveryAddress
    && eTG_PurchTableTrade.PurchId == purchTable.PurchId;


    AgreementHeaderTmp.ETGPortpalceofdischarge    =          purchaseAgreementHeaderETG.PortOfDischargeDesc;
    AgreementHeaderTmp.ETGPortplaceofloading      =          purchaseAgreementHeaderETG.PortOfLoadingDesc;
    AgreementHeaderTmp.ETGTermsOfPayment          =          purchTable.Payment;
    AgreementHeaderTmp.ETGContractNo              =          purchAgreementHeader.PurchNumberSequence;
    AgreementHeaderTmp.ETGSellerName              =          dirpartySeller.Name;
    AgreementHeaderTmp.ETGBuyerName               =          dirpartyBuyer.Name;
    AgreementHeaderTmp.ETGSellerAddress           =          int2Str(logisticsElectronicAddresSeller.Location);
    AgreementHeaderTmp.ETGBuyerAddress            =          int2Str(logisticsElectronicAddresBuyer.Location);
    AgreementHeaderTmp.ETGBuyerAddress            =           logisticspostaladdress.Address;

    if (!CurrentCompanyIsSpanishCompany())
    {
        AgreementHeaderTmp.insert();
    }

    //AgreementHeaderTmp = next initializeAgreementHeaderTmp();

    return AgreementHeaderTmp;

}

