protected void initializeQuantityCommitmentHistoryAgreementLine(AgreementConfirmationDPLineHistoryCreationParameters _parameters)
{
    // InventDim                             inventDim =
    EcoResItemSizeName                   ecoResItemSizeName;
    EcoResSize                          ecoResSize;
    AgreementLine                       AgreementLine;
    ETG_AgreementLineNotes              AgreementLineNotes;
    AgreementLineHistory                agreementLineHistory;


    next initializeQuantityCommitmentHistoryAgreementLine(_parameters);

    AgreementLine = AgreementLine::find(agreementLineHistory.AgreementLine);

    agreementLineTmp.ETGOrigin                =       InventDim::findDim(_parameters.inventDim).InventSizeId;

    while select Description from AgreementLineNotes
    where AgreementLineNotes.AgreementLine ==  AgreementLine.RecId
    {
        if(agreementLineTmp.ETGDescription)
        {
            agreementLineTmp.ETGDescription = agreementLineTmp.ETGDescription + ',' + AgreementLineNotes.Description;
        }
        else
        {
            agreementLineTmp.ETGDescription =  AgreementLineNotes.Description;
        }
    }

    if (!CurrentCompanyIsSpanishCompany())
    {
        agreementLineTmp.insert();
    }

}
